// Enrich each renewal opportunity with risk signals from the account
const today = new Date();

const enriched = $input.all().map(item => {
  const opp = item.json;

  // --- Days until close ---
  const closeDate = new Date(opp.CloseDate);
  const daysUntilClose = Math.floor((closeDate - today) / (1000 * 60 * 60 * 24));

  // --- Days since last CSM activity on Account ---
  let daysSinceActivity = 999;
  const lastActivity = opp['Account.LastActivityDate'] || opp.Account?.LastActivityDate;
  if (lastActivity) {
    daysSinceActivity = Math.floor((today - new Date(lastActivity)) / (1000 * 60 * 60 * 24));
  }

  // --- Open case count ---
  const openCases = opp.Cases?.records || [];
  const openCaseCount = openCases.length;

  // --- Urgency classification ---
  let urgency = 'Healthy';
  const riskReasons = [];

  if (daysUntilClose <= 30) {
    urgency = 'Critical';
    riskReasons.push(`Closing in ${daysUntilClose} days`);
  } else if (daysUntilClose <= 60) {
    urgency = 'Watch';
    riskReasons.push(`Closing in ${daysUntilClose} days`);
  }

  if (daysSinceActivity > 30) {
    if (urgency !== 'Critical') urgency = 'Watch';
    riskReasons.push(`No CSM activity in ${daysSinceActivity} days`);
  }

  if (openCaseCount >= 3) {
    if (urgency !== 'Critical') urgency = 'Watch';
    riskReasons.push(`${openCaseCount} open cases`);
  }

  if (opp.StageName === 'Renewal At Risk') {
    urgency = 'Critical';
    riskReasons.push('Stage: Renewal At Risk');
  }

  return {
    json: {
      oppId: opp.Id,
      oppName: opp.Name,
      amount: opp.Amount ? `$${Number(opp.Amount).toLocaleString()}` : 'N/A',
      closeDate: opp.CloseDate,
      daysUntilClose,
      stageName: opp.StageName,
      accountName: opp['Account.Name'] || opp.Account?.Name || 'Unknown',
      csmName: opp['Account.Owner.Name'] || opp.Account?.Owner?.Name || 'Unknown CSM',
      daysSinceActivity,
      openCaseCount,
      urgency,
      riskReasons,
      sfLink: `https://login.salesforce.com/${opp.Id}`
    }
  };
});

return enriched;

// Group all renewal opps into Critical / Watch / Healthy buckets
// and generate a single Slack digest message

const allOpps = $input.all().map(i => i.json);

const groups = {
  Critical: allOpps.filter(o => o.urgency === 'Critical'),
  Watch:    allOpps.filter(o => o.urgency === 'Watch'),
  Healthy:  allOpps.filter(o => o.urgency === 'Healthy')
};

const today = new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' });

let message = `📊 *Weekly Renewal Pipeline — ${today}*\n`;
message += `${allOpps.length} renewals closing within 90 days\n\n`;

const formatOpp = (o) => {
  let line = `• *${o.accountName}* — ${o.amount} — closes ${o.closeDate} (${o.daysUntilClose}d)`;
  if (o.riskReasons.length > 0) {
    line += `\n  _${o.riskReasons.join(' · ')}_`;
  }
  line += `\n  CSM: ${o.csmName} | <${o.sfLink}|View in Salesforce>`;
  return line;
};

if (groups.Critical.length > 0) {
  message += `🔴 *CRITICAL (${groups.Critical.length})*\n`;
  message += groups.Critical.map(formatOpp).join('\n') + '\n\n';
}

if (groups.Watch.length > 0) {
  message += `🟡 *WATCH (${groups.Watch.length})*\n`;
  message += groups.Watch.map(formatOpp).join('\n') + '\n\n';
}

if (groups.Healthy.length > 0) {
  message += `🟢 *HEALTHY (${groups.Healthy.length})*\n`;
  message += groups.Healthy.map(o => `• *${o.accountName}* — ${o.amount} — closes ${o.closeDate}`).join('\n');
}

return [{ json: { digestMessage: message, totalCount: allOpps.length } }];
